                <ul class="history-event-list">
                  ${historyEventRows}
                </ul>
              </div>

              <div class="modal-actions">
                <button class="btn secondary" type="button" data-action="close-history-modal">Close</button>
              </div>
            </div>
          </div>
        ` : ""}
      </ha-card>

      <style>
